sql:
SELECT DISTINCT u.user_name
FROM users u
JOIN bets b ON u.user_id = b.user_id;

SELECT COUNT(DISTINCT user_id)
FROM bets
WHERE status = 'won';

SELECT match_id, match_date
FROM matches
WHERE home_team_id = 1 OR away_team_id = 1;

external_knowledge:
- 'Ocean of bets' represents the entire dataset of bets placed;
- 'Waves of total betting volume' symbolizes the sum of all betting volumes associated with each outcome type;
- 'Ripples of average odds' refers to the mean odds for each outcome type;
- 'Currents indicating the total number of bets' signifies the count of bets for each outcome type;
- The metaphorical expressions used aim to convey the volume, variability, and frequency of betting activities in an oceanic analogy.

sql:
SELECT user_id, total_amount_bet, total_winnings 
FROM bettor_stats 
WHERE total_bets >= 10;

SELECT bet_amount 
FROM bets 
WHERE bet_id = 1;

SELECT SUM(bet_amount) AS total_bet_amount
FROM bets
WHERE user_id = 0;

SELECT match_id, bet_amount
FROM bets
WHERE user_id = 1;

SELECT outcome_type, odds 
FROM match_outcomes 
WHERE match_id = 1;

SELECT COUNT(DISTINCT match_id) AS betted_matches
FROM bets
WHERE user_id = 1;

external_knowledge:
- 'game' refers to a match;
- 'specific outcome' refers to a particular betting outcome;
- 'first match' means the match with `match_id` equal to 1;
- 'initial bet' means the bet with `bet_id` equal to 1.

sql:
SELECT outcome_type, AVG(betting_volume) AS average_betting_volume
FROM match_outcomes
GROUP BY outcome_type;

SELECT home_team_goals
FROM match_stats
WHERE match_id = 1;

SELECT COUNT(*) 
FROM user_activity 
WHERE activity_type = 'logout' AND activity_date = '2023-05-02';
